/* ---- globals.css ---- */
:root{--container:1200px;--gutter:24px;--grid-cols:12;--grid-gap:24px;--section-y:clamp(72px,10vw,160px);}
html{scroll-behavior:smooth;}
body{background:#FAFAF8;color:#14151A;font-family:var(--font-sans);-webkit-font-smoothing:antialiased;font-variant-numeric:tabular-nums;}

/* Visible 12-col grid overlay behind hero + key sections (1px warm rules @ 8% ink) */
.grid-rules{position:absolute;inset:0;pointer-events:none;z-index:0;max-width:var(--container);margin-inline:auto;
  background-image:repeating-linear-gradient(to right,transparent 0,transparent calc((100% - 11*var(--grid-gap))/12),
    rgba(20,21,26,.05) 0,rgba(20,21,26,.05) 1px,transparent 1px,transparent calc((100% - 11*var(--grid-gap))/12 + var(--grid-gap)));}

/* Scroll-reveal: progressive enhancement, NO JS dependency for final state */
.reveal{opacity:0;transform:translateY(16px);}
@supports (animation-timeline:view()){
  .reveal{animation:rise linear both;animation-timeline:view();animation-range:entry 0% cover 30%;}
  .reveal-l{animation-name:riseL} .reveal-r{animation-name:riseR}
}
@supports not (animation-timeline:view()){.reveal{opacity:1;transform:none}} /* fallback = visible */
.stagger>*{animation-delay:calc(var(--i,0)*60ms);}

/* Sticky masthead crossfades to blurred paper once scrolled (.is-scrolled via tiny IO) */
.masthead{background:transparent;border-bottom:1px solid transparent;transition:background .2s,border-color .2s,backdrop-filter .2s;}
.masthead.is-scrolled{background:rgba(250,250,248,.82);backdrop-filter:blur(8px);border-bottom-color:#E5E4DD;}

/* Focus ring */
:where(a,button,input,select,textarea,[tabindex]):focus-visible{outline:none;box-shadow:0 0 0 2px #FAFAF8,0 0 0 4px #4F46E5;border-radius:4px;}

/* Ambient light blobs (light-mode so they print; also hidden in @media print) */
.ambient-blob{position:absolute;border-radius:9999px;filter:blur(90px);mix-blend-mode:multiply;opacity:.5;pointer-events:none;z-index:0;}
.ambient-blob.a{background:rgba(99,102,241,.10);} .ambient-blob.b{background:rgba(255,154,98,.08);}

/* MOTION GUARD — mandatory */
@media (prefers-reduced-motion:reduce){*{animation:none!important;transition:none!important;}
  .reveal,.reveal-l,.reveal-r{opacity:1!important;transform:none!important;}}
/* PRINT GUARD — project ships a PDF */
@media print{.grid-rules,.ambient-blob{display:none!important;}*{animation:none!important;box-shadow:none!important;}
  .midnight-spread{background:#0E1020!important;-webkit-print-color-adjust:exact;print-color-adjust:exact;}}

/* ================= MOTION SYSTEM (all pure CSS, subtle, mechanical — never bouncy) =================
  1. SCROLL-REVEAL: .reveal opacity 0→1 + translateY(16px)→0 over 480ms swiss easing via animation-timeline:view(); @supports-not fallback resolves to visible end-state (no IntersectionObserver dependency for content). Zig-zag scenes use .reveal-l/.reveal-r (translateX ±24px). Grid children stagger 60ms via --i.
  2. DIAGRAM 'FLOW' (proof-of-liveness graft): in EVERY diagram exactly ONE connector is class 'live' — stroke-dasharray '5 6' + animation flow (stroke-dashoffset → -44) in brand-600, so a single indigo pulse travels employee→skill / trigger→outcome. Never animate more than one edge per figure.
  3. STATUS RING 'breathes' (scale 1→1.04 + opacity, 3.6s); nav live dot pulses a mint ring (pulseDot 2.4s).
  4. HOVER: cards lift translateY(-2px) + border line→line-strong (200ms); connector-map edges shift stroke to brand-600 on node hover; nav/link underlines wipe via scaleX(0→1) transform-origin-left pseudo-element.
  5. HERO orbital (D1 graft): a group of skill nodes rotates slowly (spin 40s linear) around a shared transform-origin; inner ring counter-rotates. Kept light.
  6. APPROVAL RIPPLE (the ONLY warm/mint motion): mint ring expands (ripple 4s) + checkmark stroke draws on (drawIn) — reinforces the human moment.
  7. AMBIENT: hero-only faint hairline grid drifts 0→-24px over 40s (gridDrift); two light blobs drift 22–30s.
  8. STATS pop in with a scale keyframe on reveal (no JS count-ups).
  ALL wrapped by prefers-reduced-motion (freeze to final) + print (strip animation/shadow, force Midnight exact colors). */
